import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, RouterLink, ActivatedRoute } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { NotificationService } from '../../../core/services/notification.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './login.component.html',
})
export class LoginComponent {
  email    = '';
  password = '';
  readonly loading = signal(false);

  constructor(
    private auth:     AuthService,
    private notify:   NotificationService,
    private router:   Router,
    private route:    ActivatedRoute,
  ) {}

  onSubmit(): void {
    if (!this.email || !this.password) {
      this.notify.warning('Missing fields', 'Please fill in all fields.');
      return;
    }
    this.loading.set(true);

    this.auth.login(this.email, this.password).subscribe({
      next: () => {
        this.notify.success('Welcome back!');
        const returnUrl = this.route.snapshot.queryParams['returnUrl'] || '/dashboard';
        this.router.navigateByUrl(returnUrl);
      },
      error: (e) => {
        this.notify.error('Login failed', e.error?.message ?? 'Invalid credentials');
        this.loading.set(false);
      },
    });
  }
}
<div class="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-blue-50 dark:from-slate-900 dark:to-slate-800 px-4 py-12">
  <div class="w-full max-w-md">

    <!-- Card -->
    <div class="card p-8 animate-slide-up">

      <!-- Logo -->
      <div class="text-center mb-8">
        <div class="w-14 h-14 bg-gradient-to-br from-primary-500 to-primary-700 rounded-2xl mx-auto mb-4 flex items-center justify-center text-2xl shadow-md">⚡</div>
        <h1 class="text-2xl font-bold text-slate-900 dark:text-white">Welcome back</h1>
        <p class="text-slate-500 dark:text-slate-400 text-sm mt-1">Sign in to your account</p>
      </div>

      <!-- Form -->
      <form (ngSubmit)="onSubmit()" #loginForm="ngForm" class="space-y-4">

        <div>
          <label class="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Email address</label>
          <input type="email" [(ngModel)]="email" name="email" required
            placeholder="you@example.com" class="input" autocomplete="email">
        </div>

        <div>
          <label class="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5">Password</label>
          <input type="password" [(ngModel)]="password" name="password" required
            placeholder="••••••••" class="input" autocomplete="current-password">
        </div>

        <button type="submit" [disabled]="loading() || loginForm.invalid"
          class="btn btn-primary w-full py-3 text-base font-semibold mt-2">
          <svg *ngIf="loading()" class="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z"/>
          </svg>
          {{ loading() ? 'Signing in…' : 'Sign in' }}
        </button>

      </form>

      <p class="text-center text-sm text-slate-500 dark:text-slate-400 mt-6">
        Don't have an account?
        <a routerLink="/register" class="text-primary-600 font-medium hover:underline ml-1">Sign up free</a>
      </p>

    </div>
  </div>
</div>
